1: /**
2:  * @fileoverview Shared TypeScript interfaces for the CLI portfolio.
3:  *
4:  * This module defines all data types used across the terminal engine.
5:  * Import from here instead of defining inline types to maintain consistency.
6:  *
7:  * @module types
8:  * @see {@link file:///d:/portfolio-draft/docs/terminal-engine.md} for architecture overview
9:  */
10: 
11: // ── Portfolio Data Types ──────────────────────────────────────────
12: 
13: /** Information about the portfolio owner. */
14: export interface OwnerInfo {
15:   readonly name: string;
16:   readonly handle: string;
17:   readonly host: string;
18:   readonly title: string;
19:   readonly tagline: string;
20:   readonly location: string;
21:   readonly email: string;
22:   readonly github: string;
23:   readonly linkedin: string;
24: }
25: 
26: /** A single portfolio project entry. */
27: export interface Project {
28:   readonly slug: string;
29:   readonly name: string;
30:   readonly desc: string;
31:   readonly tech: readonly string[];
32:   readonly url: string;
33:   readonly year: number;
34: }
35: 
36: /** Skill categories mapped to arrays of skill names. */
37: export interface Skills {
38:   readonly [category: string]: readonly string[];
39: }
40: 
41: /** Contact information links. */
42: export interface Contact {
43:   readonly email: string;
44:   readonly github: string;
45:   readonly linkedin: string;
46:   readonly twitter: string;
47: }
48: 
49: /** Root shape of portfolio.json. */
50: export interface PortfolioData {
51:   readonly owner: OwnerInfo;
52:   readonly about: readonly string[];
53:   readonly skills: Skills;
54:   readonly projects: readonly Project[];
55:   readonly contact: Contact;
56: }
57: 
58: // ── Terminal Theme Types ──────────────────────────────────────────
59: 
60: /**
61:  * A complete terminal color theme compatible with xterm.js ITheme.
62:  * Themes are defined in themes.ts and can be switched at runtime via
63:  * the `theme` command.
64:  */
65: export interface TerminalTheme {
66:   /** Display name (e.g. "Amber Phosphor") */
67:   readonly name: string;
68:   /** Unique key used in the `theme <name>` command */
69:   readonly key: string;
70:   /** Main text color */
71:   readonly foreground: string;
72:   /** Terminal background */
73:   readonly background: string;
74:   /** Cursor block color */
75:   readonly cursor: string;
76:   /** Text behind cursor */
77:   readonly cursorAccent: string;
78:   /** Text selection highlight */
79:   readonly selectionBackground: string;
80:   /** ANSI color 0 – Black */
81:   readonly black: string;
82:   /** ANSI color 1 – Red */
83:   readonly red: string;
84:   /** ANSI color 2 – Green */
85:   readonly green: string;
86:   /** ANSI color 3 – Yellow */
87:   readonly yellow: string;
88:   /** ANSI color 4 – Blue */
89:   readonly blue: string;
90:   /** ANSI color 5 – Magenta */
91:   readonly magenta: string;
92:   /** ANSI color 6 – Cyan */
93:   readonly cyan: string;
94:   /** ANSI color 7 – White */
95:   readonly white: string;
96:   /** ANSI color 8 – Bright Black */
97:   readonly brightBlack: string;
98:   /** ANSI color 9 – Bright Red */
99:   readonly brightRed: string;
100:   /** ANSI color 10 – Bright Green */
101:   readonly brightGreen: string;
102:   /** ANSI color 11 – Bright Yellow */
103:   readonly brightYellow: string;
104:   /** ANSI color 12 – Bright Blue */
105:   readonly brightBlue: string;
106:   /** ANSI color 13 – Bright Magenta */
107:   readonly brightMagenta: string;
108:   /** ANSI color 14 – Bright Cyan */
109:   readonly brightCyan: string;
110:   /** ANSI color 15 – Bright White */
111:   readonly brightWhite: string;
112: }
113: 
114: // ── Command System Types ──────────────────────────────────────────
115: 
116: /**
117:  * Abstraction layer between commands and the terminal renderer.
118:  * Commands write output through this interface, making them
119:  * testable and decoupled from xterm.js internals.
120:  */
121: export interface TerminalWriter {
122:   /** Write text without a trailing newline. */
123:   write(text: string): void;
124:   /** Write text followed by \r\n. */
125:   writeln(text: string): void;
126:   /** Clear the entire terminal screen. */
127:   clear(): void;
128: }
129: 
130: /**
131:  * Handler function signature for terminal commands.
132:  * Each command receives parsed arguments and a writer for output.
133:  * Return a Promise for async commands (e.g. chatbot API calls).
134:  */
135: export type CommandHandler = (
136:   args: string[],
137:   writer: TerminalWriter
138: ) => void | Promise<void>;
139: 
140: /**
141:  * Metadata for a registered command (used by help, tab completion).
142:  */
143: export interface CommandInfo {
144:   /** The command name (what the user types). */
145:   readonly name: string;
146:   /** Short description shown in `help` output. */
147:   readonly description: string;
148:   /** Usage example (e.g. "theme <name>"). */
149:   readonly usage?: string;
150:   /** The handler function. */
151:   readonly handler: CommandHandler;
152: }
