1: /**
2:  * @fileoverview Command registry and interpreter for the CLI portfolio.
3:  *
4:  * All terminal commands are registered here as typed handlers.
5:  * The interpreter parses user input and dispatches to the correct handler.
6:  *
7:  * ## Adding a new command
8:  * 1. Create a handler function: `(args, writer) => void`
9:  * 2. Register it in `COMMANDS` map at the bottom of this file
10:  * 3. Add the name to CONFIG.commands in config.ts for tab completion
11:  * 4. Update the help text in cmdHelp()
12:  *
13:  * @module commands
14:  */
15: 
16: import type { TerminalWriter, CommandHandler, PortfolioData } from './types';
17: import { CONFIG } from './config';
18: import { getPortfolioData } from './data';
19: import * as fs from './filesystem';
20: import { renderNeofetch } from './neofetch';
21: import { startChat, handleInput as chatInput, isActive as isChatActive } from './chatbot';
22: import { getAllThemes, getTheme } from './themes';
23: 
24: // ── State ─────────────────────────────────────────────────────────
25: 
26: /** Current theme key (tracked for neofetch display). */
27: let _currentTheme = CONFIG.defaultTheme;
28: 
29: /** Callback to apply a theme to the xterm instance. */
30: let _onThemeChange: ((themeKey: string) => void) | null = null;
31: 
32: /** Callback to launch snake game (needs DOM container). */
33: let _onSnakeLaunch: (() => void) | null = null;
34: 
35: /** Callback to reload the page. */
36: let _onReset: (() => void) | null = null;
37: 
38: /** Callback to clear the terminal. */
39: let _onClear: (() => void) | null = null;
40: 
41: // ── Setup ─────────────────────────────────────────────────────────
42: 
43: /**
44:  * Configure command system callbacks.
45:  * Call once during terminal initialization.
46:  */
47: export function setupCommands(opts: {
48:   onThemeChange: (themeKey: string) => void;
49:   onSnakeLaunch: () => void;
50:   onReset: () => void;
51:   onClear: () => void;
52: }): void {
53:   _onThemeChange = opts.onThemeChange;
54:   _onSnakeLaunch = opts.onSnakeLaunch;
55:   _onReset = opts.onReset;
56:   _onClear = opts.onClear;
57: }
58: 
59: /** Set the current theme key (used by neofetch display). */
60: export function setCurrentTheme(key: string): void {
61:   _currentTheme = key;
62: }
63: 
64: // ── Command Handlers ──────────────────────────────────────────────
65: 
66: const cmdHelp: CommandHandler = (_args, writer) => {
67:   writer.writeln('');
68:   writer.writeln('\x1b[1;38;2;255;140;0mAvailable Commands\x1b[0m');
69:   writer.writeln('');
70:   writer.writeln('  \x1b[38;2;255;176;0mhelp\x1b[0m           Show this message');
71:   writer.writeln('  \x1b[38;2;255;176;0mls\x1b[0m             List directory contents');
72:   writer.writeln('  \x1b[38;2;255;176;0mcd <dir>\x1b[0m       Change directory');
73:   writer.writeln('  \x1b[38;2;255;176;0mcat <file>\x1b[0m     Print file contents');
74:   writer.writeln('  \x1b[38;2;255;176;0mabout\x1b[0m          Quick bio');
75:   writer.writeln('  \x1b[38;2;255;176;0mskills\x1b[0m         Technical skills overview');
76:   writer.writeln('  \x1b[38;2;255;176;0mprojects\x1b[0m       Project showcase');
77:   writer.writeln('  \x1b[38;2;255;176;0mcontact\x1b[0m        How to reach me');
78:   writer.writeln('  \x1b[38;2;255;176;0mneofetch\x1b[0m       System info display');
79:   writer.writeln('  \x1b[38;2;255;176;0mtheme <name>\x1b[0m   Switch color theme');
80:   writer.writeln('  \x1b[38;2;255;176;0mezra\x1b[0m           Chat with AI assistant');
81:   writer.writeln('  \x1b[38;2;255;176;0msnake\x1b[0m          Play Snake game');
82:   writer.writeln('  \x1b[38;2;255;176;0mclear\x1b[0m          Clear the screen');
83:   writer.writeln('  \x1b[38;2;255;176;0mreset\x1b[0m          Reload portfolio');
84:   writer.writeln('');
85:   writer.writeln('  \x1b[38;2;85;85;85mHint: try exploring with ls and cd...\x1b[0m');
86:   writer.writeln('');
87: };
88: 
89: const cmdAbout: CommandHandler = (_args, writer) => {
90:   const data = getPortfolioData();
91:   if (!data) { writer.writeln('Data not loaded yet.'); return; }
92: 
93:   writer.writeln('');
94:   writer.writeln(`\x1b[1;38;2;255;140;0m${data.owner.name}\x1b[0m  —  ${data.owner.title}`);
95:   writer.writeln(`\x1b[38;2;136;136;136m${data.owner.location}\x1b[0m`);
96:   writer.writeln('');
97:   data.about.forEach(line => writer.writeln(`  ${line}`));
98:   writer.writeln('');
99: };
100: 
101: const cmdSkills: CommandHandler = (_args, writer) => {
102:   const data = getPortfolioData();
103:   if (!data) { writer.writeln('Data not loaded yet.'); return; }
104: 
105:   writer.writeln('');
106:   for (const [cat, items] of Object.entries(data.skills)) {
107:     writer.writeln(`\x1b[1;38;2;255;140;0m${cat}\x1b[0m`);
108:     writer.writeln(`  ${items.join('  ')}`);
109:     writer.writeln('');
110:   }
111: };
112: 
113: const cmdProjects: CommandHandler = (_args, writer) => {
114:   const data = getPortfolioData();
115:   if (!data) { writer.writeln('Data not loaded yet.'); return; }
116: 
117:   writer.writeln('');
118:   for (const p of data.projects) {
119:     writer.writeln(`\x1b[1;38;2;255;208;96m${p.name}\x1b[0m  (${p.year})`);
120:     writer.writeln(`  ${p.desc}`);
121:     writer.writeln(`  \x1b[38;2;136;136;136m${p.tech.join(', ')}\x1b[0m`);
122:     writer.writeln(`  ${p.url}`);
123:     writer.writeln('');
124:   }
125:   writer.writeln(`Type \x1b[1;38;2;255;176;0mcd projects && ls\x1b[0m to explore project files.`);
126:   writer.writeln('');
127: };
128: 
129: const cmdContact: CommandHandler = (_args, writer) => {
130:   const data = getPortfolioData();
131:   if (!data) { writer.writeln('Data not loaded yet.'); return; }
132: 
133:   const c = data.contact;
134:   writer.writeln('');
135:   writer.writeln(`  \x1b[38;2;255;176;0mEmail\x1b[0m    ${c.email}`);
136:   writer.writeln(`  \x1b[38;2;255;176;0mGitHub\x1b[0m   ${c.github}`);
137:   writer.writeln(`  \x1b[38;2;255;176;0mLinkedIn\x1b[0m ${c.linkedin}`);
138:   if (c.twitter) writer.writeln(`  \x1b[38;2;255;176;0mTwitter\x1b[0m  ${c.twitter}`);
139:   writer.writeln('');
140: };
141: 
142: const cmdNeofetch: CommandHandler = (_args, writer) => {
143:   const data = getPortfolioData();
144:   renderNeofetch(writer, data, _currentTheme);
145: };
146: 
147: const cmdTheme: CommandHandler = (args, writer) => {
148:   if (!args[0]) {
149:     // List available themes
150:     writer.writeln('');
151:     writer.writeln('\x1b[1;38;2;255;140;0mAvailable Themes\x1b[0m');
152:     writer.writeln('');
153:     for (const [key, theme] of getAllThemes()) {
154:       const marker = key === _currentTheme ? ' \x1b[38;2;0;230;118m← active\x1b[0m' : '';
155:       writer.writeln(`  \x1b[38;2;255;176;0m${key.padEnd(12)}\x1b[0m ${theme.name}${marker}`);
156:     }
157:     writer.writeln('');
158:     writer.writeln('Usage: \x1b[38;2;255;208;96mtheme <name>\x1b[0m');
159:     writer.writeln('');
160:     return;
161:   }
162: 
163:   const theme = getTheme(args[0]);
164:   if (!theme) {
165:     writer.writeln(`\x1b[31mtheme: '${args[0]}' not found. Type \x1b[1mtheme\x1b[0;31m to see available themes.\x1b[0m`);
166:     return;
167:   }
168: 
169:   _currentTheme = theme.key;
170:   _onThemeChange?.(theme.key);
171:   writer.writeln(`\x1b[38;2;0;230;118mTheme switched to ${theme.name}\x1b[0m`);
172: };
173: 
174: const cmdEzra: CommandHandler = async (_args, writer) => {
175:   await startChat(writer);
176: };
177: 
178: const cmdSnake: CommandHandler = (_args, writer) => {
179:   writer.writeln('\x1b[1;38;2;255;140;0mSNAKE\x1b[0m — Arrow keys to move. Q to quit.');
180:   _onSnakeLaunch?.();
181: };
182: 
183: const cmdClear: CommandHandler = (_args, _writer) => {
184:   _onClear?.();
185: };
186: 
187: const cmdReset: CommandHandler = (_args, _writer) => {
188:   _onReset?.();
189: };
190: 
191: // ── Command Registry ──────────────────────────────────────────────
192: 
193: /**
194:  * Map of command name → handler function.
195:  * To add a new command, add an entry here.
196:  */
197: const COMMANDS = new Map<string, CommandHandler>([
198:   ['help', cmdHelp],
199:   ['ls', (args, w) => fs.ls(args, w)],
200:   ['cd', (args, w) => fs.cd(args, w)],
201:   ['cat', (args, w) => fs.cat(args, w)],
202:   ['about', cmdAbout],
203:   ['skills', cmdSkills],
204:   ['projects', cmdProjects],
205:   ['contact', cmdContact],
206:   ['neofetch', cmdNeofetch],
207:   ['theme', cmdTheme],
208:   ['ezra', cmdEzra],
209:   ['snake', cmdSnake],
210:   ['clear', cmdClear],
211:   ['reset', cmdReset],
212: ]);
213: 
214: // ── Interpreter ───────────────────────────────────────────────────
215: 
216: /**
217:  * Parse and execute a command string.
218:  *
219:  * @param input - Raw input from the terminal
220:  * @param writer - Terminal writer for output
221:  * @returns Promise that resolves when the command completes
222:  */
223: export async function interpret(input: string, writer: TerminalWriter): Promise<void> {
224:   const trimmed = input.trim();
225:   if (!trimmed) return;
226: 
227:   // If Ezra chatbot is active, route input there
228:   if (isChatActive()) {
229:     await chatInput(trimmed, writer);
230:     return;
231:   }
232: 
233:   const parts = trimmed.split(/\s+/);
234:   const name = parts[0].toLowerCase();
235:   const args = parts.slice(1);
236: 
237:   const handler = COMMANDS.get(name);
238:   if (handler) {
239:     await handler(args, writer);
240:   } else {
241:     writer.writeln(`\x1b[31m${name}: command not found. Type \x1b[1mhelp\x1b[0;31m for usage.\x1b[0m`);
242:   }
243: }
244: 
245: /**
246:  * Get the current prompt string with the current working directory.
247:  * Uses ANSI colors for the joel@portfolio:~$ format.
248:  */
249: export function getPrompt(): string {
250:   const cwdPath = fs.getCwd();
251:   return `\x1b[1;38;2;255;140;0m${CONFIG.handle}@${CONFIG.host}\x1b[0m:\x1b[38;2;255;208;96m${cwdPath}\x1b[0m$ `;
252: }
253: 
