1: /**
2:  * @fileoverview Virtual filesystem for the CLI portfolio.
3:  *
4:  * Provides ls, cd, cat operations over a simulated directory tree
5:  * built from portfolio data. The filesystem is initialized once
6:  * from PortfolioData and remains in memory.
7:  *
8:  * ## Directory Structure
9:  * ```
10:  * ~ (home)
11:  * ├── about/
12:  * │   ├── bio.txt
13:  * │   └── experience.txt
14:  * ├── skills/
15:  * │   ├── languages.txt
16:  * │   ├── frameworks.txt
17:  * │   └── devops.txt
18:  * ├── projects/
19:  * │   ├── <slug>.md  (one per project)
20:  * ├── contact/
21:  * │   └── links.txt
22:  * └── README.md
23:  * ```
24:  *
25:  * @module filesystem
26:  */
27: 
28: import type { PortfolioData, TerminalWriter } from './types';
29: 
30: // ── State ─────────────────────────────────────────────────────────
31: 
32: /** Directory tree: path → list of child names */
33: const fs = new Map<string, string[]>();
34: 
35: /** Current working directory */
36: let cwd = '~';
37: 
38: /** Cached portfolio data reference */
39: let _data: PortfolioData | null = null;
40: 
41: // ── Initialization ────────────────────────────────────────────────
