143:     model: CONFIG.mimoModel,
144:     max_tokens: CONFIG.mimoMaxTokens,
145:     messages,
146:   };
147: 
148:   const res = await fetch(CONFIG.mimoEndpoint, {
149:     method: 'POST',
150:     headers: {
151:       'Content-Type': 'application/json',
152:       'Authorization': `Bearer ${CONFIG.mimoApiKey}`,
153:     },
154:     body: JSON.stringify(body),
155:   });
