14: const H = 20;   // tiles tall
15: const DELAY = 110; // ms per tick
16: 
17: // ── State ─────────────────────────────────────────────────────────
18: 
19: let canvas: HTMLCanvasElement | null = null;
20: let ctx: CanvasRenderingContext2D | null = null;
21: let running = false;
22: let timer: ReturnType<typeof setTimeout> | null = null;
23: let dir = { x: 1, y: 0 };
24: let nextDir = { x: 1, y: 0 };
25: let body: Array<{ x: number; y: number }> = [];
26: let food = { x: 0, y: 0 };
27: let score = 0;
28: let _onQuit: (() => void) | null = null;
