30: // ── Keyboard Handler ──────────────────────────────────────────────
31: 
32: function onKey(e: KeyboardEvent): void {
33:   const map: Record<string, { x: number; y: number }> = {
34:     ArrowUp:    { x: 0, y: -1 },
35:     ArrowDown:  { x: 0, y: 1 },
36:     ArrowLeft:  { x: -1, y: 0 },
37:     ArrowRight: { x: 1, y: 0 },
38:   };
39: 
40:   if (map[e.key] && !(dir.x === -map[e.key].x && dir.y === -map[e.key].y)) {
41:     nextDir = map[e.key];
42:     e.preventDefault();
43:   }
44: 
45:   if (e.key === 'q' || e.key === 'Q') {
46:     cleanup();
47:   }
48: }
