50: // ── Game Logic ────────────────────────────────────────────────────
51: 
52: function spawnFood(): void {
53:   do {
54:     food = {
55:       x: Math.floor(Math.random() * W),
56:       y: Math.floor(Math.random() * H),
57:     };
58:   } while (body.some(s => s.x === food.x && s.y === food.y));
59: }
60: 
61: function resetGame(): void {
62:   dir = { x: 1, y: 0 };
63:   nextDir = { x: 1, y: 0 };
64:   body = [{ x: 13, y: 10 }, { x: 12, y: 10 }, { x: 11, y: 10 }];
65:   score = 0;
66:   spawnFood();
67:   draw();
68: }
69: 
70: function tick(): void {
71:   if (!running) return;
72:   dir = nextDir;
73: 
74:   const head = {
75:     x: (body[0].x + dir.x + W) % W,
76:     y: (body[0].y + dir.y + H) % H,
77:   };
78: 
79:   // Self-collision
80:   if (body.some(s => s.x === head.x && s.y === head.y)) {
81:     gameOver();
82:     return;
83:   }
84: 
85:   body.unshift(head);
86: 
87:   if (head.x === food.x && head.y === food.y) {
88:     score++;
89:     spawnFood();
90:   } else {
91:     body.pop();
92:   }
93: 
94:   draw();
95:   timer = setTimeout(tick, DELAY);
96: }
